const perf = $('Fetch Week Performance').all().map(i => i.json);
const pipeline = $('Fetch Pipeline Status').all().map(i => i.json);
const trends = $('Fetch Top Trends').all().map(i => i.json);

let totalViews = 0, totalLikes = 0, totalComments = 0;
let published = 0;
const byPlatform = {};
const byContentType = {};

for (const p of perf) {
  const views = p.properties?.Views?.number || 0;
  const likes = p.properties?.Likes?.number || 0;
  const comments = p.properties?.Comments?.number || 0;
  const platform = p.properties?.Platform?.select?.name || 'Unknown';
  const contentType = p.properties?.ContentType?.select?.name || 'Unknown';

  totalViews += views; totalLikes += likes; totalComments += comments;

  if (!byPlatform[platform]) byPlatform[platform] = { views: 0, posts: 0 };
  byPlatform[platform].views += views;
  byPlatform[platform].posts++;

  if (!byContentType[contentType]) byContentType[contentType] = { score: 0, posts: 0 };
  byContentType[contentType].score += p.properties?.PerformanceScore?.number || 0;
  byContentType[contentType].posts++;
}

// Pipeline stats
const statusCounts = {};
for (const p of pipeline) {
  const status = p.properties?.Status?.select?.name || 'Unknown';
  statusCounts[status] = (statusCounts[status] || 0) + 1;
  if (status === 'Published' || status === 'Viral') published++;
}

// Top performers
const sorted = perf.sort((a, b) => (b.properties?.PerformanceScore?.number || 0) - (a.properties?.PerformanceScore?.number || 0));
const topContent = sorted.slice(0, 3).map(p => p.properties?.VideoTitle?.title?.[0]?.plain_text || 'Video').join(', ');

// Top trends
const topTrends = trends.slice(0, 5).map(t => t.properties?.Name?.title?.[0]?.plain_text || 'Trend').join(', ');

const avgEngRate = perf.length ? (perf.reduce((s, p) => s + (p.properties?.EngagementRate?.number || 0), 0) / perf.length).toFixed(2) : 0;

return [{
  json: {
    weekOf: new Date().toISOString().split('T')[0],
    totalViews, totalLikes, totalComments,
    postsPublished: published,
    avgEngagementRate: parseFloat(avgEngRate),
    topPerformingContent: topContent,
    platformBreakdown: JSON.stringify(byPlatform),
    contentTypeBreakdown: JSON.stringify(byContentType),
    pipelineStatus: JSON.stringify(statusCounts),
    topTrends,
    totalPosts: perf.length
  }
}];

